#include <bits/stdc++.h>
using namespace std;

int n, m, k;
vector<int> l[505];
bool f[505][505][25];
int ans[505][25];

int main() {
    cin >> n >> m >> k;
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        l[u].push_back(v);
        l[v].push_back(u);
    }
    for (int i = 1; i <= n; i++) f[i][i][0] = true;
    for (int s = 0; s < k; s++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (f[i][j][s]) {
                    for (int k : l[j]) {
                        f[i][k][s + 1] = true;
                        // f[k][i][s + 1] = true;
                    }
                }
            }
        }
    }
    for (int s = 1; s <= k; s++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (f[i][j][s]) {
                    ans[i][s]++;
                }
            }
        }
    }
    for (int i = 1; i <= n; i++) {
        for (int s = 1; s <= k; s++) {
            cout << ans[i][s] << ' ';
        }
        cout << endl;
    }
    return 0;
}
